import React from 'react';
import { LinkText, MenuText, ProjectInfoText, SkillsText } from 'component';
import styles from './Project.module.scss';

const Project = (props) => {
  const {
    project,
    lang
  } = props
  return (
    <article className={styles.project}>
      <MenuText title={lang.project} id={"project"} />
      {project.map((m, i) => {
        return (
          <div key={i} className={styles.projectList}>
            <div className={styles.introduce}>
              <ProjectInfoText title={lang[m.title]} info={lang[m.info]} alert={m.alert && lang['alert']} />
            </div>
            <div className={styles.hoverSkill}>
              <SkillsText skills={m.skills} />
            </div>
            <div className={styles.hoverLink}>
              <LinkText git={m.git} site={m.site} />
            </div>
          </div>
        )
      })}
    </article>
  );
};

export default Project;