import React from 'react';
import styles from './ProjectInfoText.module.scss';

const ProjectInfoText = (props) => {
  const {
    title,
    info,
    alert
  } = props
  return (
    <div className={styles.info}>
      <h1>{title}</h1>
      <h3>{info}</h3>
      <h4>{alert ? alert : ''}</h4>
    </div>
  );
};

export default ProjectInfoText;