import React, { Component } from 'react';
import { Footer, Header, Language, Nav, Project } from 'component';
import { ApiLanguage, ApiProject } from 'api';
import styles from './LayoutContainer.module.scss';

class LayoutContainer extends Component {

  changeLanguage = async (lang) => {
    await ApiLanguage(lang).then(res => this.setState({ lang: res, current: lang }))
  }

  componentDidMount() {
    ApiLanguage().then(res => this.setState({ lang: res }))
    ApiProject().then(res => this.setState({ project: res }))
  }

  constructor(props) {
    super(props)

    this.state = {
      lang: [],
      project: [],
      current: 'en',
      changeLanguage: this.changeLanguage
    }
  }

  render() {
    const {
      changeLanguage,
      current,
      lang,
      project
    } = this.state
    return (
      <div className={styles.wrapper}>
        <Nav lang={lang} />
        <Header lang={lang} />
        <Language lang={lang} changeLanguage={changeLanguage} current={current} />
        <Project project={project} lang={lang} />
        <Footer />
      </div>
    );
  }
}

export default LayoutContainer;